import java.util.HashMap;

class State {
    HashMap<Character, State> next = new HashMap<>();
    int length;
    State link;
}

class SuffixAutomaton {
    private State root;
    private State last;

    public SuffixAutomaton() {
        root = new State();
        last = root;
    }

    public void extend(char c) {
        State curr = new State();
        curr.length = last.length + 1;
        State p = last;
        while (p != null && !p.next.containsKey(c)) {
            p.next.put(c, curr);
            p = p.link;
        }
        if (p == null) {
            curr.link = root;
        } else {
            State q = p.next.get(c);
            if (p.length + 1 == q.length) {
                curr.link = q;
            } else {
                State clone = new State();
                clone.length = p.length + 1;
                clone.next = new HashMap<>(q.next);
                clone.link = q.link;
                q.link = clone;
                curr.link = clone;
                while (p != null && p.next.get(c) == q) {
                    p.next.put(c, clone);
                    p = p.link;
                }
            }
        }
        last = curr;
    }

    public boolean containsSuffix(String s) {
        State node = root;
        for (char c : s.toCharArray()) {
            if (!node.next.containsKey(c)) {
                return false;
            }
            node = node.next.get(c);
        }
        return true;
    }
}

