#include <iostream>
#include <unordered_map>
#include <string>

class State {
public:
    std::unordered_map<char, State*> next;
    int length;
    State* link;
    State() : length(0), link(nullptr) {}
};

class SuffixAutomaton {
private:
    State* root;
    State* last;

public:
    SuffixAutomaton() {
        root = new State();
        last = root;
    }

    void extend(char c) {
        State* curr = new State();
        curr->length = last->length + 1;
        State* p = last;
        while (p && p->next.find(c) == p->next.end()) {
            p->next[c] = curr;
            p = p->link;
        }
        if (!p) {
            curr->link = root;
        } else {
            State* q = p->next[c];
            if (p->length + 1 == q->length) {
                curr->link = q;
            } else {
                State* clone = new State();
                clone->length = p->length + 1;
                clone->next = q->next;
                clone->link = q->link;
                q->link = clone;
                curr->link = clone;
                while (p && p->next[c] == q) {
                    p->next[c] = clone;
                    p = p->link;
                }
            }
        }
        last = curr;
    }

    bool containsSuffix(const std::string& s) {
        State* node = root;
        for (char c : s) {
            if (node->next.find(c) == node->next.end()) {
                return false;
            }
            node = node->next[c];
        }
        return true;
    }

    ~SuffixAutomaton() {
        deleteState(root);
    }

private:
    void deleteState(State* s) {
        if (!s) return;
        for (auto& pair : s->next) {
            deleteState(pair.second);
        }
        delete s;
    }
};

int main() {
    SuffixAutomaton automaton;
    std::string word = "banana";
    for (char c : word) {
        automaton.extend(c);
    }
    std::cout << "Contains suffix \"ana\": " << (automaton.containsSuffix("ana") ? "true" : "false") << "\n";
    std::cout << "Contains suffix \"xyz\": " << (automaton.containsSuffix("xyz") ? "true" : "false") << "\n";
    return 0;
}
// Output: Contains suffix "ana": true
// Output: Contains suffix "xyz": false

