} SuffixAutomaton;

State* createState() {
    State* s = (State*)malloc(sizeof(State));
    s->length = 0;
    s->link = NULL;
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        s->next[i] = NULL;
    }
    return s;
}

SuffixAutomaton* createAutomaton() {
    SuffixAutomaton* sa = (SuffixAutomaton*)malloc(sizeof(SuffixAutomaton));
    sa->root = createState();
    sa->last = sa->root;
    return sa;
}

void extend(SuffixAutomaton* sa, char c) {
    State* curr = createState();
    curr->length = sa->last->length + 1;
    State* p = sa->last;
    int idx = c - 'a';
    while (p && !p->next[idx]) {
        p->next[idx] = curr;
        p = p->link;
    }
    if (!p) {
        curr->link = sa->root;
    } else {
        State* q = p->next[idx];
        if (p->length + 1 == q->length) {
            curr->link = q;
        } else {
            State* clone = createState();
            clone->length = p->length + 1;
            for (int i = 0; i < ALPHABET_SIZE; i++) {
                clone->next[i] = q->next[i];
            }
            clone->link = q->link;
            q->link = clone;
            curr->link = clone;
            while (p && p->next[idx] == q) {
                p->next[idx] = clone;
                p = p->link;
            }
        }
    }
    sa->last = curr;
}

int containsSuffix(SuffixAutomaton* sa, const char* s) {
    State* node = sa->root;
    for (int i = 0; s[i]; i++) {
        int idx = s[i] - 'a';
        if (!node->next[idx]) {
            return 0;
        }
        node = node->next[idx];
    }
    return 1;
}

void freeState(State* s) {
    if (!s) return;
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        freeState(s->next[i]);
    }
    free(s);
}

void freeAutomaton(SuffixAutomaton* sa) {
    freeState(sa->root);
    free(sa);
}

